1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	const INSURANCE_VALUES: Record<string, number> = {
14	  sword: 1000,
15	  amulet: 600,
16	  staff: 800,
17	  potion: 400,
18	  rune: 250,
19	  moonstone: 250,
20	};
21	
22	const DEDUCTIBLE = 100;
23	const CAP_MULTIPLIER = 2;
24	
25	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
26	type Customer = { yearsWithMHPCO: number };
27	type Damage = { itemType: string; amount: number };
28	type Incident = { cause: string; damages: Damage[] };
29	type QuoteStep = { op: "quote"; items: Item[] };
30	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
31	type Step = QuoteStep | ClaimStep;
32	type Scenario = { customer: Customer; steps: Step[] };
33	
34	const enchantmentOf = (item: Item): number => item.enchantment ?? 0;
35	
36	const CURSE_SURCHARGE_RATE = 0.5;
37	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
38	const HIGH_ENCHANTMENT_THRESHOLD = 5;
39	const LOYALTY_DISCOUNT_RATE = 0.2;
40	const LOYALTY_YEARS_THRESHOLD = 2;
41	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
42	
43	type QuoteResult = { premium: number };
44	type ClaimResult = { payout: number; remainingCap: number };
45	type StepResult = QuoteResult | ClaimResult;
46	
47	const COMPONENT_BLOCK_SIZE = 3;
48	const COMPONENT_BLOCK_PREMIUM = 60;
49	
50	const isComponentBlock = (group: Item[]): boolean => group.length === COMPONENT_BLOCK_SIZE;
51	
52	const sumByLookup = (items: Item[], table: Record<string, number>): number =>
53	  items.reduce((sum, item) => sum + table[item.type], 0);
54	
55	const groupByType = (items: Item[]): Item[][] =>
56	  Object.values(Object.groupBy(items, (item) => item.type));
57	
58	const basePremiumForGroup = (group: Item[]): number =>
59	  isComponentBlock(group) ? COMPONENT_BLOCK_PREMIUM : sumByLookup(group, BASE_PREMIUMS);
60	
61	const basePremiumFor = (items: Item[]): number =>
62	  groupByType(items).reduce((sum, group) => sum + basePremiumForGroup(group), 0);
63	
64	type RateRule<T> = { rate: number; applies: (input: T) => boolean };
65	
66	const SURCHARGE_RULES: RateRule<Item>[] = [
67	  { rate: CURSE_SURCHARGE_RATE, applies: (item) => !!item.cursed },
68	  {
69	    rate: HIGH_ENCHANTMENT_SURCHARGE_RATE,
70	    applies: (item) => enchantmentOf(item) >= HIGH_ENCHANTMENT_THRESHOLD,
71	  },
72	];
73	
74	const surchargeForRule = (items: Item[], rule: RateRule<Item>): number =>
75	  items
76	    .filter(rule.applies)
77	    .reduce((sum, item) => sum + BASE_PREMIUMS[item.type] * rule.rate, 0);
78	
79	const surchargesFor = (items: Item[]): number =>
80	  SURCHARGE_RULES.reduce((total, rule) => total + surchargeForRule(items, rule), 0);
81	
82	type PolicyContext = { customer: Customer; isFollowUp: boolean };
83	
84	const POLICY_DISCOUNT_RULES: RateRule<PolicyContext>[] = [
85	  {
86	    rate: LOYALTY_DISCOUNT_RATE,
87	    applies: ({ customer }) => customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD,
88	  },
89	  {
90	    rate: FOLLOW_UP_DISCOUNT_RATE,
91	    applies: ({ isFollowUp }) => isFollowUp,
92	  },
93	];
94	
95	const policyDiscountsFor = (base: number, context: PolicyContext): number =>
96	  POLICY_DISCOUNT_RULES.filter((rule) => rule.applies(context)).reduce(
97	    (total, rule) => total + base * rule.rate,
98	    0,
99	  );
100	
101	const validateItems = (items: Item[]): void => {
102	  for (const item of items) {
103	    if (!(item.type in BASE_PREMIUMS)) {
104	      throw new Error(`Unknown item type: "${item.type}"`);
105	    }
106	  }
107	};
108	
109	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): QuoteResult => {
110	  validateItems(items);
111	  const base = basePremiumFor(items);
112	  const surcharges = surchargesFor(items);
113	  const discounts = policyDiscountsFor(base, { customer, isFollowUp });
114	  const firstInsurance = base * FIRST_INSURANCE_RATE;
115	  return {
116	    premium: Math.ceil(base + surcharges - discounts + firstInsurance + PROCESSING_FEE),
117	  };
118	};
119	
120	const isFollowUpStep = (index: number): boolean => index > 0;
121	
122	type Policy = { items: Item[]; remainingCap: number };
123	
124	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
125	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
126	
127	const createPolicy = (items: Item[]): Policy => ({
128	  items,
129	  remainingCap: CAP_MULTIPLIER * sumByLookup(items, INSURANCE_VALUES),
130	});
131	
132	const reimbursementFor = (item: Item, amount: number): number =>
133	  enchantmentOf(item) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
134	    ? amount * HIGH_ENCHANTMENT_PAYOUT_RATE
135	    : amount;
136	
137	const payoutForDamage = (damage: Damage, policy: Policy): number => {
138	  const item = policy.items.find((it) => it.type === damage.itemType);
139	  const reimbursement = item ? reimbursementFor(item, damage.amount) : damage.amount;
140	  return Math.max(0, reimbursement - DEDUCTIBLE);
141	};
142	
143	const countBy = <T>(xs: T[], keyOf: (x: T) => string): Record<string, number> =>
144	  xs.reduce<Record<string, number>>((acc, x) => {
145	    const key = keyOf(x);
146	    acc[key] = (acc[key] ?? 0) + 1;
147	    return acc;
148	  }, {});
149	
150	const validateDamages = (damages: Damage[], items: Item[]): void => {
151	  const damageCounts = countBy(damages, (d) => d.itemType);
152	  const itemCounts = countBy(items, (i) => i.type);
153	  for (const [type, count] of Object.entries(damageCounts)) {
154	    if (count > (itemCounts[type] ?? 0)) {
155	      throw new Error(`Damage for "${type}" exceeds insured count`);
156	    }
157	  }
158	};
159	
160	const processClaim = (policy: Policy, incident: Incident): ClaimResult => {
161	  validateDamages(incident.damages, policy.items);
162	  const uncappedPayout = incident.damages.reduce(
163	    (sum, damage) => sum + payoutForDamage(damage, policy),
164	    0,
165	  );
166	  const payout = Math.floor(Math.min(uncappedPayout, policy.remainingCap));
167	  policy.remainingCap -= payout;
168	  return { payout, remainingCap: policy.remainingCap };
169	};
170	
171	type StepContext = { customer: Customer; index: number; policies: Policy[] };
172	
173	const STEP_HANDLERS: {
174	  [K in Step["op"]]: (step: Extract<Step, { op: K }>, context: StepContext) => StepResult;
175	} = {
176	  quote: ({ items }, { customer, index, policies }) => {
177	    policies[index] = createPolicy(items);
178	    return quotePremium(items, customer, isFollowUpStep(index));
179	  },
180	  claim: (step, { policies }) => processClaim(policies[step.policy], step.incident),
181	};
182	
183	const runStep = (step: Step, context: StepContext): StepResult =>
184	  (STEP_HANDLERS[step.op] as (s: Step, c: StepContext) => StepResult)(step, context);
185	
186	export const processScenario = ({ customer, steps }: Scenario): { results: StepResult[] } => {
187	  const policies: Policy[] = [];
188	  const results = steps.map((step, index) => runStep(step, { customer, index, policies }));
189	  return { results };
190	};
